import{c as a,Q as n,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"内核内存与 slab","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/09-内核内存与slab.md","filePath":"osLearning/09-内核内存与slab.md","lastUpdated":1781095972000}'),e={name:"osLearning/09-内核内存与slab.md"};function p(l,s,o,h,c,r){return n(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="内核内存与-slab" tabindex="-1">内核内存与 slab <a class="header-anchor" href="#内核内存与-slab" aria-label="Permalink to &quot;内核内存与 slab&quot;">​</a></h1><p>新手看 <code>free -h</code> 最常见的惊吓:16GB 的机器,<code>free</code> 只剩 500MB——&quot;内存被谁吃光了?!&quot;然后慌忙重启服务,甚至有人写了定时清缓存的 cron。这都是冤案:<strong>那 11GB 的 buff/cache 不是被吃了,是 Linux 拿空闲内存做了缓存,你的程序要用时它随时让出来</strong>。要看懂这笔账,你得知道内核自己是怎么管内存的——它不能用 malloc(它自己就是 malloc 的底座),它有自己的两层体系:<strong>buddy 管物理页,slab 管小对象</strong>。每次 fork、每次 open、每个新连接,背后都是这套体系在毫秒间分配 task_struct、inode、socket buffer。这一篇把内核这本账讲清楚。</p><blockquote><p>一句话先记住:<strong>内核内存 = buddy(按 2 的幂分配物理页)+ slab(在页上为每种内核对象切好&quot;专用货架&quot;)</strong>,而剩下的空闲内存几乎全被拿去做 <strong>page cache</strong>——所以<strong>看可用内存要看 available,不是 free</strong>。slab 让 task_struct / inode 这类高频小对象的分配接近零成本,<strong>这是 Linux 能扛住每秒十万级 fork / open / accept 的底层原因</strong>。</p></blockquote><hr><h2 id="一、内核为什么不能用-malloc" tabindex="-1">一、内核为什么不能用 malloc <a class="header-anchor" href="#一、内核为什么不能用-malloc" aria-label="Permalink to &quot;一、内核为什么不能用 malloc&quot;">​</a></h2><p>用户态的 malloc 那么成熟,内核抄一份不行吗?不行,内核面对三条用户态没有的死规矩:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 内核不能缺页</span></span>
<span class="line"><span>   用户态访问没分配的页 → 缺页中断 → 内核来兜底</span></span>
<span class="line"><span>   内核自己缺页 → 谁兜底?没人,直接死锁/崩溃</span></span>
<span class="line"><span>   → 内核分到的内存必须立刻有物理页,不能玩&quot;先记账后给钱&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 中断上下文不能睡眠</span></span>
<span class="line"><span>   malloc 内部可能等内存回收(等就是睡眠)</span></span>
<span class="line"><span>   中断处理函数绝不能睡</span></span>
<span class="line"><span>   → 必须提供&quot;原子分配&quot;:要么立刻给,要么立刻失败</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. DMA 要求物理连续</span></span>
<span class="line"><span>   网卡/磁盘控制器直接往物理内存写,不经过 MMU</span></span>
<span class="line"><span>   → 给设备的缓冲区必须物理连续,虚拟连续没用</span></span></code></pre></div><p>所以内核自己搭了一套,分两层:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────┐</span></span>
<span class="line"><span>│  slab / slub                │ ← 在页上切小对象(kmalloc、kmem_cache_*)</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  buddy allocator            │ ← 管物理页(alloc_pages)</span></span>
<span class="line"><span>├─────────────────────────────┤</span></span>
<span class="line"><span>│  物理内存                    │</span></span>
<span class="line"><span>└─────────────────────────────┘</span></span></code></pre></div><p>眼熟吗?<strong>和用户态&quot;glibc 切小块 / 内核批发大块&quot;是同一个思想</strong>——批发零售两级结构,只是这次批发商是 buddy,零售商是 slab。</p><hr><h2 id="二、buddy-分配器-用-2-的幂驯服碎片" tabindex="-1">二、buddy 分配器:用 2 的幂驯服碎片 <a class="header-anchor" href="#二、buddy-分配器-用-2-的幂驯服碎片" aria-label="Permalink to &quot;二、buddy 分配器:用 2 的幂驯服碎片&quot;">​</a></h2><p>buddy 把物理内存按 2 的幂分块,每档(order)各维护一条空闲链表:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order 0:  1 页 = 4KB      free list: [页A] → [页B] → ...</span></span>
<span class="line"><span>order 1:  2 页 = 8KB      free list: [页对] → ...</span></span>
<span class="line"><span>order 2:  4 页 = 16KB</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>order 10: 1024 页 = 4MB   ← kmalloc 的天花板就来自这</span></span></code></pre></div><p><strong>分配</strong>:要 8KB → 找 order 1 的链表;空了就去拆一个 order 2 的块,劈成两半,用一半挂一半。</p><p><strong>释放</strong>:还 order 1 的块时,看它的&quot;伙伴(buddy)&quot;——同 order、地址相邻、合起来正好是一个 order 2 块的那一半——是否也空闲。<strong>空闲就合并成 order 2,然后递归向上继续试合并</strong>。</p><p>为什么死磕 2 的幂?三个理由:<strong>伙伴好找</strong>(伙伴的地址和自己只差一个 bit,异或一下就出来)、<strong>碎片可控</strong>(小块总有机会合回大块)、<strong>分配快</strong>(O(log n) 定位档位)。</p><p>观测:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/buddyinfo</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Node 0, zone   Normal   100  50  20  10  5  2  1  0  0  0  0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#                          o0  o1  o2  o3 ...              o10</span></span></code></pre></div><p>每个数字是该 order 的空闲块数。<strong>右边高 order 全是 0 = 系统已经凑不出大块连续物理内存了</strong>。这不是理论问题——高 PPS 场景网卡驱动要分配多页连续缓冲,碎片化的机器上分配失败,<strong>表现就是莫名其妙的丢包</strong>。</p><hr><h2 id="三、slab-给每种内核对象开-专用货架" tabindex="-1">三、slab:给每种内核对象开&quot;专用货架&quot; <a class="header-anchor" href="#三、slab-给每种内核对象开-专用货架" aria-label="Permalink to &quot;三、slab:给每种内核对象开&quot;专用货架&quot;&quot;">​</a></h2><h3 id="_3-1-没有-slab-的世界" tabindex="-1">3.1 没有 slab 的世界 <a class="header-anchor" href="#_3-1-没有-slab-的世界" aria-label="Permalink to &quot;3.1 没有 slab 的世界&quot;">​</a></h3><p>内核的分配负载长这样:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每秒 fork 100 次     → 100 个 task_struct(每个约 2KB)</span></span>
<span class="line"><span>每秒 open 1000 次    → 1000 组 file / inode / dentry</span></span>
<span class="line"><span>每秒 accept 10 万次  → 10 万个 sock 结构</span></span></code></pre></div><p>全是<strong>固定大小、生灭极快</strong>的小对象。每次都找 buddy 拿一整页?2KB 的对象占 4KB 的页,浪费一半;而且分配路径太长,扛不住这个频率。</p><h3 id="_3-2-slab-的解法-按类型预制" tabindex="-1">3.2 slab 的解法:按类型预制 <a class="header-anchor" href="#_3-2-slab-的解法-按类型预制" aria-label="Permalink to &quot;3.2 slab 的解法:按类型预制&quot;">​</a></h3><p><strong>为每种内核数据结构维护一个专属 cache</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>task_struct cache:</span></span>
<span class="line"><span>  从 buddy 批发一页,预先划成 N 个 task_struct 大小的格子</span></span>
<span class="line"><span>  分配:从格子里拿一个,O(1)</span></span>
<span class="line"><span>  释放:放回格子,O(1)(连初始化都能省——格子里留着上次的构造状态)</span></span>
<span class="line"><span>  格子用完 → 再找 buddy 批发一页</span></span>
<span class="line"><span></span></span>
<span class="line"><span>inode cache、dentry cache、sock cache……每种对象一套</span></span></code></pre></div><p>这就是 slab。<strong>fork / open / accept 的内存分配被压到近乎零成本,Linux 能撑百万级 socket,这是底层支柱之一</strong>。</p><p>历史上有三个实现:<code>slab</code>(初版,思想来自 Solaris)、<code>slub</code>(现在的 Linux 默认,更简洁更快)、<code>slob</code>(嵌入式小内存版)。<strong>现在跑的都是 slub,但所有人嘴上还是叫 slab</strong>,内核 API 也还是 <code>kmem_cache_*</code>:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 内核模块给自己的结构建 cache:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> kmem_cache </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">my_cache </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kmem_cache_create</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my_obj&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        sizeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my_obj), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, SLAB_HWCACHE_ALIGN, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> my_obj </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> kmem_cache_alloc</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(my_cache, GFP_KERNEL);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kmem_cache_free</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(my_cache, o);</span></span></code></pre></div><h3 id="_3-3-观测-slabtop" tabindex="-1">3.3 观测:slabtop <a class="header-anchor" href="#_3-3-观测-slabtop" aria-label="Permalink to &quot;3.3 观测:slabtop&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slabtop</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  OBJS  ACTIVE  USE  OBJ SIZE  SLABS  OBJ/SLAB  CACHE SIZE  NAME</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 100000  90000  90%   256.0K    100        1      24.4MB    task_struct</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 200000 180000  90%   192.0K    200        1      38.4MB    inode_cache</span></span></code></pre></div><p><strong>&quot;系统内存涨了但所有进程的 RSS 都解释不了&quot;时,slabtop 是第一现场</strong>——经常是 dentry / inode 缓存被海量小文件操作撑起来了(可调 <code>vm.vfs_cache_pressure</code> 让内核更积极地回收它们,默认 100,调大更积极)。</p><hr><h2 id="四、kmalloc-vs-vmalloc-内核里的-两种-malloc" tabindex="-1">四、kmalloc vs vmalloc:内核里的&quot;两种 malloc&quot; <a class="header-anchor" href="#四、kmalloc-vs-vmalloc-内核里的-两种-malloc" aria-label="Permalink to &quot;四、kmalloc vs vmalloc:内核里的&quot;两种 malloc&quot;&quot;">​</a></h2><p>内核代码自己要内存时,有两个常用入口:</p><table tabindex="0"><thead><tr><th></th><th><code>kmalloc(size, flags)</code></th><th><code>vmalloc(size)</code></th></tr></thead><tbody><tr><td>物理连续性</td><td><strong>连续</strong>(走 slab / buddy)</td><td>虚拟连续,物理可以碎</td></tr><tr><td>能否 DMA</td><td>能</td><td><strong>不能</strong>(设备不认虚拟地址)</td></tr><tr><td>大小上限</td><td>约 4MB(buddy order 10)</td><td>几百 MB 没问题</td></tr><tr><td>速度</td><td>快</td><td>慢一点(要逐页建页表映射)</td></tr><tr><td>碎片敏感</td><td>大块在碎片化机器上会失败</td><td>不敏感</td></tr></tbody></table><p>选择口诀:<strong>小对象、要 DMA、要快 → kmalloc;大块、不碰设备 → vmalloc</strong>。</p><p>kmalloc 还要带一个 <code>GFP_*</code> 标志,告诉内核&quot;我现在处于什么上下文&quot;:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GFP_KERNEL:   普通进程上下文,缺内存可以睡着等回收</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GFP_ATOMIC:   中断 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 自旋锁里,绝不能睡——要么立刻给要么失败</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GFP_NOIO:     回收时禁止发 </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">IO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(防止 IO 路径上的递归死锁)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GFP_DMA:      限定低 </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">16MB</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 物理内存(伺候老 ISA 设备)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">__GFP_ZERO:   分配顺便清零</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">__GFP_NOFAIL: 死磕到拿到为止(慎用)</span></span></code></pre></div><p>经典死法:<strong>中断处理函数里用了 GFP_KERNEL</strong>——它一睡眠,整个 CPU 的中断处理卡死。中断里只能 GFP_ATOMIC。</p><hr><h2 id="五、page-cache-那-11gb-消失的内存" tabindex="-1">五、page cache:那 11GB&quot;消失的内存&quot; <a class="header-anchor" href="#五、page-cache-那-11gb-消失的内存" aria-label="Permalink to &quot;五、page cache:那 11GB&quot;消失的内存&quot;&quot;">​</a></h2><p>现在回答开头的惊吓。看这个输出:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">free</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#         total   used   free   shared  buff/cache  available</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mem:     16Gi    4Gi   500Mi   100Mi      11Gi       11Gi</span></span></code></pre></div><p>那 11GB 的 buff/cache 是 <strong>page cache</strong>:你每次 <code>read</code> 一个文件,内核顺手把数据留在内存里,下次再读同一块就不打磁盘了。<strong>Linux 的哲学是&quot;空闲内存就是浪费的内存&quot;——能拿来做缓存的全拿去</strong>。关键在于这些页是&quot;随叫随让&quot;的:程序要内存时内核直接回收它们。</p><p>所以铁律是:<strong>看 available,别看 free</strong>。available 才是&quot;程序还能用多少&quot;。</p><p>写也走 page cache,而且更妙:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>write() → 数据进 page cache,标记 dirty → 立即返回(没碰磁盘!)</span></span>
<span class="line"><span>后台 writeback 线程定期把 dirty 页刷盘</span></span></code></pre></div><p><strong>这就是 write 快得不像在写磁盘的原因——它确实没在写磁盘</strong>。代价是掉电会丢没刷盘的数据,所以数据库在关键节点调 <code>fsync(fd)</code> 强制落盘(阻塞到数据真正在盘上)。</p><p>dirty 页的水位由两个参数管:<code>vm.dirty_background_ratio</code>(默认 10,超过就启动后台刷)和 <code>vm.dirty_ratio</code>(默认 20,超过就强制同步刷,<strong>业务线程会被卡住</strong>)。重写入的服务通常把它们调小,把&quot;攒一大坨突然刷盘 stall 几秒&quot;摊平成持续小流量。</p><p>顺带认识 <strong>tmpfs</strong>:<code>/tmp</code>、<code>/run</code>、<code>/dev/shm</code> 这些挂载点的&quot;文件&quot;其实直接存在 page cache 里,读写飞快但关机即焚。<strong>坑:tmpfs 占的内存算 used 不算 cache</strong>——往 /dev/shm 倒了 4GB 文件,used 莫名多 4GB,经常没人想得起来。</p><hr><h2 id="六、内存吃紧时-回收的优先级链" tabindex="-1">六、内存吃紧时:回收的优先级链 <a class="header-anchor" href="#六、内存吃紧时-回收的优先级链" aria-label="Permalink to &quot;六、内存吃紧时:回收的优先级链&quot;">​</a></h2><p>物理内存不够了,内核按这个顺序自救:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 回收 page cache(干净页直接丢,dirty 页先刷盘)</span></span>
<span class="line"><span>2. 回收 slab 里可回收的部分(主要是 dentry / inode 缓存)</span></span>
<span class="line"><span>3. 把冷的匿名页换到 swap</span></span>
<span class="line"><span>4. 都不行 → OOM Killer 杀进程(06 篇讲过选人规则)</span></span></code></pre></div><p>第 3 步的积极性由 <code>vm.swappiness</code>(0-100)控制:0 是几乎不 swap、优先砍 cache,默认 60,100 是积极 swap 保 cache。<strong>数据库服务器设 1</strong>——宁可缓存少点,绝不让热数据被换出去(被换出的页再访问就是毫秒级主缺页,p99 当场去世)。</p><p>还有个看起来诱人的开关:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/sys/vm/drop_caches</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 1=清 page cache,2=清 dentry/inode,3=全清</span></span></code></pre></div><p><strong>只配出现在测试环境</strong>(比如做干净的 IO 基准测试)。生产上清缓存等于把所有热数据扔了,接下来每个请求都打磁盘,<strong>性能瞬间塌方</strong>——开头说的那种&quot;定时清缓存的 cron&quot;就是在定时自残。</p><hr><h2 id="七、内核这本账去哪查-proc-meminfo" tabindex="-1">七、内核这本账去哪查:/proc/meminfo <a class="header-anchor" href="#七、内核这本账去哪查-proc-meminfo" aria-label="Permalink to &quot;七、内核这本账去哪查:/proc/meminfo&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/meminfo</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MemTotal:       16384000 kB</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MemFree:          500000 kB</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Buffers:          200000 kB   ← 块设备缓存</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cached:        11000000 kB   ← page cache(含 tmpfs!)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Slab:           1000000 kB   ← slab 总占用</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># SReclaimable:    800000 kB   ←   其中可回收(dentry/inode 为主)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># SUnreclaim:      200000 kB   ←   其中不可回收</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># KernelStack:      80000 kB   ← 内核栈,每个线程 16KB</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># PageTables:      100000 kB   ← 页表本身占的内存</span></span></code></pre></div><p>一个真实的&quot;内存失踪案&quot;排查:total 16GB、所有进程 RSS 加起来 4GB、cache 才 1GB,剩下的呢?翻 meminfo——<code>PageTables</code> 占了 5GB(几百个大进程,<strong>页表自己就是 GB 级开销</strong>,06 篇讲的多级页表不是免费的),或者 <code>KernelStack</code> 占 2GB(几十万个线程,每个白送内核 16KB)。<strong>用户态工具看不见的内存,全在这个文件里对账</strong>。</p><hr><h2 id="八、容器的内存账-cgroup" tabindex="-1">八、容器的内存账:cgroup <a class="header-anchor" href="#八、容器的内存账-cgroup" aria-label="Permalink to &quot;八、容器的内存账:cgroup&quot;">​</a></h2><p>Docker / K8s 限制容器内存,底层就是 cgroup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ...</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 约等于:</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1G</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory/mycontainer/memory.limit_in_bytes</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $$</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/memory/mycontainer/cgroup.procs</span></span></code></pre></div><p>内核为每个 cgroup 单独记账(RSS + page cache),超限就触发 <strong>cgroup 内的 OOM Killer</strong>。两个著名的坑:</p><ul><li><strong>老版 JVM 看不见 cgroup</strong>,按宿主机内存自动算 -Xmx——容器限 2G,JVM 按 64G 的机器给自己定了 16G 的堆,起来没多久就 OOMKilled。Java 10+ 的 <code>-XX:+UseContainerSupport</code> 修了(配合 07 篇的 MaxRAMPercentage)</li><li><strong>page cache 也算进 cgroup 的账</strong>——容器里大量读写文件,cache 把 limit 顶满,看起来&quot;进程没用多少内存却 OOM 了&quot;</li></ul><p>容器底层的完整机制详见 25 篇。</p><hr><h2 id="九、numa-内存还分远近" tabindex="-1">九、NUMA:内存还分远近 <a class="header-anchor" href="#九、numa-内存还分远近" aria-label="Permalink to &quot;九、NUMA:内存还分远近&quot;">​</a></h2><p>多 socket 服务器上,内存条物理上挂在不同 CPU 下面:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Node 0:CPU 0-15  + 64GB 本地内存</span></span>
<span class="line"><span>Node 1:CPU 16-31 + 64GB 本地内存</span></span>
<span class="line"><span>跨 node 访问 → 走 socket 间互联,延迟约翻倍</span></span></code></pre></div><p>内核分配策略默认&quot;优先本地 node,不够再去远端&quot;。排查和绑定:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numactl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hardware</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                            # 看拓扑</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numastat</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                                      # numa_miss 高 = 跨 node 严重</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numactl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cpunodebind=0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --membind=0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./app</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 绑死 node 0</span></span></code></pre></div><p>NUMA 对性能的完整影响(以及为什么数据库要绑核)放到下一篇和 CPU 缓存一起讲。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>把 buff/cache 当&quot;被吃掉的内存&quot;</strong>——那是随叫随让的缓存,看 available 才是真可用</li><li><strong>生产环境 drop_caches</strong>——热数据全扔,接下来所有请求打磁盘,这是自残不是优化</li><li><strong>kmalloc 申请大块</strong>——上限 4MB 且碎片化时失败,大块用 vmalloc</li><li><strong>中断上下文用 GFP_KERNEL</strong>——可能睡眠 = 死锁,中断里只有 GFP_ATOMIC</li><li><strong>数据库机器不调 swappiness</strong>——默认 60 会把热页换出去,p99 被主缺页打飞,设 1</li><li><strong>内存失踪不查 /proc/meminfo</strong>——PageTables / KernelStack / SUnreclaim 这些隐形大户只在这里现形</li><li><strong>不会用 slabtop</strong>——dentry / inode 缓存吃掉几个 GB 时,进程视角永远找不到凶手</li><li><strong>dirty 水位不调</strong>——重写入服务攒一大坨 dirty 页突然同步刷盘,业务 stall 几秒</li><li><strong>容器里跑老 JVM 不开容器感知</strong>——按宿主机内存定堆大小,必被 OOMKilled</li><li><strong>忘了 page cache 算 cgroup 的账</strong>——容器内大量文件 IO 也能把 limit 顶爆</li><li><strong>把 vmalloc 当 kmalloc 用</strong>——物理不连续,给 DMA 用直接出事</li><li><strong>tmpfs 当普通磁盘使</strong>——它占的是内存且算 used,往 /dev/shm 倒大文件等于偷偷吃内存</li></ol><hr><p>下一篇:<code>10-CPU缓存与一致性.md</code>,内存层的最后一块拼图,也是最影响并发性能的一块——MESI 协议怎么让多核看到一致的内存、false sharing 为什么能让多线程比单线程还慢 10 倍、NUMA 跨 socket 的真实代价,以及为什么高性能代码必须按 cache line(64 字节)设计数据结构。</p>`,85)])])}const g=a(e,[["render",p]]);export{k as __pageData,g as default};
